1340:
SELECT SUM(CASE WHEN SUBSTR(T1.event_date, 1, 4) = '2019' THEN T2.spent ELSE 0 END) - SUM(CASE WHEN SUBSTR(T1.event_date, 1, 4) = '2020' THEN T2.spent ELSE 0 END) AS difference
FROM event AS T1
JOIN budget AS T2 ON T1.event_id = T2.link_to_event;

1148:
SELECT CAST(COUNT(*) AS REAL) * 100 / COUNT(id) AS percentage
FROM Player
WHERE height < 180 AND overall_rating > 70;

352:
SELECT CAST(COUNT(CASE WHEN f.language = 'Chinese Simplified' THEN c.id ELSE NULL END) AS REAL) * 100 / COUNT(c.id) AS percentage
FROM cards c
JOIN foreign_data f ON c.uuid = f.uuid;

487:
SELECT CAST(SUM(CASE WHEN cardKingdomFoilId IS NOT NULL AND cardKingdomId IS NOT NULL THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(*) AS percentage_incredibly_powerful_cards
FROM cards
WHERE setCode = 'Coldsnap';

226:
SELECT CAST(SUM(CASE WHEN bond_type = '=' THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(*) AS "percent"
FROM bond
WHERE molecule_id = 'TR008';

47:
SELECT COUNT(CDSCode) / 12 AS MonthlyAverage
FROM schools
WHERE YEAR(OpenDate) = 1980 AND County = 'Alameda' AND DOC = 52;

92:
SELECT COUNT(district_id) AS num_districts
FROM district
WHERE A11 BETWEEN 6000 AND 10000;

118:
SELECT CAST(COUNT(*) AS REAL) * 100 / COUNT(loan_id) AS percentage_running_loans
FROM loan
WHERE amount < 100000 AND status = 'C';
